module shift_register
(
  input clk,
  input reset,
  input load,
  input [7:0] data_in,
  output reg serial_out
);

  reg [7:0] flip_flop;

  always @(posedge clk or posedge reset) begin
    if (reset) begin
      flip_flop <= 8'b0;
      serial_out <= 1'b0;
    end
    else if (load) begin
      flip_flop <= data_in;
      serial_out <= data_in[7];
    end
    else begin
      serial_out <= flip_flop[7];
      flip_flop <= {flip_flop[6:0], 1'b0};
    end
  end

endmodule
